using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;

namespace McpServer;

/// <summary>
/// MCP tools that wrap the Open-Meteo REST API.
/// The MCP SDK discovers tools by scanning for [McpServerToolType] classes
/// and [McpServerTool] methods. Constructor parameters are resolved from DI.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools
{
    private readonly HttpClient _http;

    // The SDK resolves this via the DI container registered in Program.cs.
    public WeatherTools(HttpClient httpClient)
    {
        _http = httpClient;
    }

    [McpServerTool, Description("Get current weather for a location by latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.open-meteo.com/v1/forecast" +
                  $"?latitude={latitude}&longitude={longitude}" +
                  $"&current=temperature_2m,wind_speed_10m";

        var result = await _http.GetFromJsonAsync<WeatherResponse>(url, cancellationToken);

        if (result?.Current is null)
            return "No weather data available for the given coordinates.";

        return $"Temperature: {result.Current.Temperature}°C, " +
               $"Wind speed: {result.Current.WindSpeed} km/h";
    }

    [McpServerTool, Description("Look up coordinates for a city name.")]
    public async Task<string> GeocodeCityName(
        [Description("City name to search for")] string city,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://geocoding-api.open-meteo.com/v1/search?name={Uri.EscapeDataString(city)}&count=1";
        var result = await _http.GetFromJsonAsync<GeocodeResponse>(url, cancellationToken);

        if (result?.Results is not { Count: > 0 })
            return $"Could not find coordinates for '{city}'.";

        var loc = result.Results[0];
        return $"{loc.Name}: latitude={loc.Latitude}, longitude={loc.Longitude}";
    }
}

// --- JSON response models ---------------------------------------------------

public sealed class WeatherResponse
{
    [JsonPropertyName("current")]
    public CurrentWeather? Current { get; set; }
}

public sealed class CurrentWeather
{
    [JsonPropertyName("temperature_2m")]
    public double Temperature { get; set; }

    [JsonPropertyName("wind_speed_10m")]
    public double WindSpeed { get; set; }
}

public sealed class GeocodeResponse
{
    [JsonPropertyName("results")]
    public List<GeocodeResult>? Results { get; set; }
}

public sealed class GeocodeResult
{
    [JsonPropertyName("name")]
    public string Name { get; set; } = "";

    [JsonPropertyName("latitude")]
    public double Latitude { get; set; }

    [JsonPropertyName("longitude")]
    public double Longitude { get; set; }
}

